import React, { useState } from "react";
import {
  Box,
  AppBar,
  Toolbar,
  Typography,
  Container as MuiContainer,
  IconButton,
  Drawer,
} from "@mui/material";
import MenuIcon from "@mui/icons-material/Menu";
import { NavLink } from "react-router-dom";
import { Nav } from "react-bootstrap";
import { Card, Row, Col } from "react-bootstrap";
import Login from "./login.js";
import ResourceSearch from "./resource-search.js";
import ModerationForm from "./moderation.js";
import NewPassword from "./new-password.js";
import RateResource from "./rate-resource.js";
import Register from "./register.js";
import PasswordReset from "./reset-password.js";
import ResourceReport from "./resource-report.js";
import UpdateUserRole from "./update-user-role.js";
import UploadTaggingResource from "./file-upload-tagging.js";
import SubjectView from "./subject-view.js";
import FAQ from "./faq.js";
import AboutUs from "./about-us.js";
import OER from "./oer.js";
import Contributors from "./contributors.js";
import Self from "./sdl.js";
import Analytics from "./analytics.js";

const Home = () => {
  const [searchQuery, setSearchQuery] = useState("");
  const [activeSection, setActiveSection] = useState("overview");
  const [menuOpen, setMenuOpen] = useState(false);

  const handleSearch = (e) => {
    e.preventDefault();
    console.log("Search query:", searchQuery);
  };

  const handleMenuToggle = () => {
    setMenuOpen(!menuOpen);
  };

  // Rendering dashboard content from the previous dashboard.js
  const renderDashboardContent = () => {
    return (
      <MuiContainer fluid>
        <Row>
          <Col lg="3" sm="6">
            <Card className="card-stats">
              <Card.Body>
                <Row>
                  <Col xs="5">
                    <div className="icon-big text-center icon-warning">
                      <i className="nc-icon nc-light-3 text-success"></i>
                    </div>
                  </Col>
                  <Col xs="7">
                    <div className="numbers">
                      <p className="card-category">Revenue</p>
                      <Card.Title as="h4">$ 1,345</Card.Title>
                    </div>
                  </Col>
                </Row>
              </Card.Body>
            </Card>
          </Col>
        </Row>
      </MuiContainer>
    );
  };

  const routes = [
    { name: "Home", path: "/", icon: "nc-icon nc-bank" },
    {
      name: "Subject View",
      path: "subject-view",
      icon: "nc-icon nc-book-bookmark",
    },
    {
      name: "Search Resources",
      path: "resource-search",
      icon: "nc-icon nc-zoom-split",
    },
    {
      name: "Contribute",
      path: "file-upload",
      icon: "nc-icon nc-cloud-upload-94",
    },

    { name: "Other Useful OERs", path: "oer", icon: "nc-icon nc-globe-2" },
    {
      name: "Rate Resources",
      path: "rate-resource",
      icon: "nc-icon nc-check-2",
    },
    { name: "Moderate Resources", path: "moderate", icon: "nc-icon nc-paper" },
    { name: "Contributors", path: "contributors", icon: "nc-icon nc-user-run" },
    {
      name: "Self-Directed Learning",
      path: "self-directed",
      icon: "nc-icon nc-hat-3",
    },
    { name: "Login", path: "login", icon: "nc-icon nc-lock-circle-open" },
    {
      name: "Account Creation",
      path: "register",
      icon: "nc-icon nc-single-02",
    },
    {
      name: "Password Reset",
      path: "reset-password",
      icon: "nc-icon nc-refresh-69",
    },
    { name: "New Reset", path: "new-password", icon: "nc-icon nc-key-25" },
    { name: "Analytics", path: "analytics", icon: "nc-icon nc-chart-pie-36" },
    { name: "About Us", path: "about-us", icon: "nc-icon nc-badge" },
    { name: "FAQ", path: "faq", icon: "nc-icon nc-support-17" },
    {
      name: "Resource Report",
      path: "resource-report",
      icon: "nc-icon nc-bullet-list-67",
    },
    {
      name: "Update User Role",
      path: "update-user-role",
      icon: "nc-icon nc-settings-gear-65",
    },
  ];

  const renderSectionContent = () => {
    switch (activeSection) {
      case "subject-view":
        return <SubjectView />;
      case "resource-search":
        return <ResourceSearch />;
      case "file-upload":
        return <UploadTaggingResource />;
      case "oer":
        return <OER />;
      case "contributors":
        return <Contributors />;
      case "self-directed":
        return <Self />;
      case "register":
        return <Register />;
      case "reset-password":
        return <PasswordReset />;
      case "new-password":
        return <NewPassword />;
      case "about-us":
        return <AboutUs />;
      case "faq":
        return <FAQ />;
      case "login":
        return <Login />;
      case "analytics":
        return <Analytics />;
      case "moderate":
        return <ModerationForm />;
      case "rate-resource":
        return <RateResource />;
      case "resource-report":
        return <ResourceReport />;
      case "update-user-role":
        return <UpdateUserRole />;
      case "dashboard":
        return renderDashboardContent();
      default:
        return <Typography variant="h5">Welcome to Share2Teach</Typography>;
    }
  };

  const activeRoute = (routeName) => {
    return window.location.pathname.includes(routeName) ? "active" : "";
  };

  return (
    <Box sx={{ display: "flex", height: "100vh", bgcolor: "#0000" }}>
      {/* AppBar with Menu Icon */}
      <AppBar position="static" sx={{ bgcolor: "#4caf50" }}>
        <Toolbar>
          <IconButton
            edge="start"
            color="inherit"
            aria-label="menu"
            onClick={handleMenuToggle} // Toggle Nav visibility
          >
            <MenuIcon />
          </IconButton>
          <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
            Share2Teach
          </Typography>
        </Toolbar>
      </AppBar>

      {/* Drawer to display Nav when menu icon is clicked */}
      <Drawer anchor="left" open={menuOpen} onClose={handleMenuToggle}>
        <Nav
          className="flex-column"
          style={{ width: "240px", backgroundColor: "#2c7b2f" }}
        >
          {routes.map((prop, key) => {
            if (!prop.redirect) {
              return (
                <li
                  className={
                    prop.upgrade ? "active active-pro" : activeRoute(prop.path)
                  }
                  key={key}
                >
                  <NavLink
                    to={prop.path}
                    className="nav-link"
                    activeClassName="active"
                    style={{ color: "white", padding: "10px" }}
                  >
                    <i className={prop.icon} />
                    <p>{prop.name}</p>
                  </NavLink>
                </li>
              );
            }
            return null;
          })}
        </Nav>
      </Drawer>

      {/* Main Content */}
      <Box sx={{ flexGrow: 1, padding: 2, overflowY: "auto" }}>
        <MuiContainer sx={{ padding: 2, overflowY: "auto" }}>
          <div className="text-center mb-4">
            <img
              src="https://services.nwu.ac.za/sites/services.nwu.ac.za/files/files/designs-branding/NWU-Stacked-Logo-Black-Digital.png"
              alt="Share2Teach"
              className="img-fluid"
              width={50}
            />
          </div>
          <Box
            sx={{
              padding: 2,
              bgcolor: "#ffffff",
              borderRadius: 2,
              animation: "fadeIn 0.5s ease",
              "@keyframes fadeIn": {
                "0%": { opacity: 0 },
                "100%": { opacity: 1 },
              },
            }}
          >
            {renderSectionContent()}
          </Box>
        </MuiContainer>
      </Box>
    </Box>
  );
};

export default Home;
